export function parseSettleAuctionInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedSettleAuctionInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 9) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 9,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === SOLANS_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      settler: getNextAccount(),
      config: getNextAccount(),
      seller: getNextAccount(),
      sellerSolansAccount: getNextOptionalAccount(),
      nameRecord: getNextAccount(),
      auction: getNextAccount(),
      bidVault: getNextAccount(),
      solansMint: getNextAccount(),
      tokenProgram: getNextAccount(),
    },
    data: getSettleAuctionInstructionDataDecoder().decode(instruction.data),
  };
}
